COMMENT ON COLUMN public.view_log.has_access IS 'Whether the user who initiated the view had read access to the item being viewed.';


--
-- Name: COLUMN view_log.context; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.context IS 'The context of the view, can be collection, question, or dashboard. Only for cards.';


--
-- Name: COLUMN view_log.embedding_client; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.embedding_client IS 'Used by the embedding team to track SDK usage';


--
-- Name: COLUMN view_log.embedding_sdk_version; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.embedding_sdk_version IS 'Used by the embedding team to track SDK version usage';


--
-- Name: COLUMN view_log.auth_method; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.auth_method IS 'Authentication method used (e.g. jwt, saml, api-key, public, guest, etc.)';


--
-- Name: COLUMN view_log.tenant_id; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.tenant_id IS 'Tenant ID of the user who generated this view';


--
-- Name: COLUMN view_log.embedding_hostname; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.embedding_hostname IS 'Hostname from Origin header, PII';


--
-- Name: COLUMN view_log.embedding_path; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.embedding_path IS 'Path from Referer header (query params stripped), PII';


--
-- Name: COLUMN view_log.user_agent; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.user_agent IS 'User-Agent header, PII';


--
-- Name: COLUMN view_log.ip_address; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.ip_address IS 'Client IP address, PII';


--
-- Name: COLUMN view_log.sanitized_user_agent; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.sanitized_user_agent IS 'Human-friendly parsed User-Agent (e.g. Browser (Chrome/Windows)), PII';


--
-- Name: COLUMN view_log.embedding_route; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.embedding_route IS 'API route surface (e.g. public, guest-embed, metabot, agent-api)';


--
-- Name: COLUMN view_log.metabase_version; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON COLUMN public.view_log.metabase_version IS 'Metabase server version tag at time of insert';


--
-- Name: v_view_log; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_view_log AS
 SELECT id,
    "timestamp",
    COALESCE(user_id, 0) AS user_id,
    model AS entity_type,
    model_id AS entity_id,
    (((model)::text || '_'::text) || model_id) AS entity_qualified_id,
    embedding_client,
    embedding_route,
        CASE
            WHEN ((embedding_client)::text ~~ '%-preview'::text) THEN true
            ELSE false
        END AS is_preview,
    has_access,
    context,
    embedding_sdk_version,
    metabase_version,
    auth_method,
    tenant_id,
    embedding_hostname,
    embedding_path,
    user_agent,
    sanitized_user_agent,
    ip_address
   FROM public.view_log;


ALTER VIEW public.v_view_log OWNER TO postgres;

