--
-- Name: v_metabot_conversations _RETURN; Type: RULE; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW public.v_metabot_conversations AS
 SELECT c.id AS conversation_id,
    c.created_at,
    c.user_id,
    c.summary,
    COALESCE((((u.first_name)::text || ' '::text) || (u.last_name)::text), (u.email)::text) AS user_display_name,
    count(m.id) AS message_count,
    count(
        CASE
            WHEN ((m.role)::text = 'user'::text) THEN 1
            ELSE NULL::integer
        END) AS user_message_count,
    count(
        CASE
            WHEN ((m.role)::text = 'assistant'::text) THEN 1
            ELSE NULL::integer
        END) AS assistant_message_count,
    COALESCE(max(a.total_tokens), (0)::bigint) AS total_tokens,
    COALESCE(max(a.prompt_tokens), (0)::bigint) AS prompt_tokens,
    COALESCE(max(a.completion_tokens), (0)::bigint) AS completion_tokens,
    max(m.created_at) AS last_message_at,
    ( SELECT mm.profile_id
           FROM public.metabot_message mm
          WHERE (((mm.conversation_id)::text = (c.id)::text) AND ((mm.role)::text = 'assistant'::text) AND (mm.deleted_at IS NULL))
          ORDER BY mm.created_at, mm.id
         LIMIT 1) AS profile_id,
    ( SELECT
                CASE mm.profile_id
                    WHEN 'internal'::text THEN 'Internal'::text
                    WHEN 'embedding_next'::text THEN 'Embedding'::text
                    WHEN 'nlq'::text THEN 'NLQ'::text
                    WHEN 'sql'::text THEN 'SQL'::text
                    WHEN 'slackbot'::text THEN 'Slackbot'::text
                    WHEN 'transforms_codegen'::text THEN 'Transforms codegen'::text
                    WHEN 'document-generate-content'::text THEN 'Documents'::text
                    ELSE mm.profile_id
                END AS profile_id
           FROM public.metabot_message mm
          WHERE (((mm.conversation_id)::text = (c.id)::text) AND ((mm.role)::text = 'assistant'::text) AND (mm.deleted_at IS NULL))
          ORDER BY mm.created_at, mm.id
         LIMIT 1) AS profile_name,
    ( SELECT pg.name
           FROM (public.permissions_group_membership pgm
             JOIN public.permissions_group pg ON ((pg.id = pgm.group_id)))
          WHERE ((pgm.user_id = c.user_id) AND (pg.id <> 1))
          ORDER BY pg.name
         LIMIT 1) AS group_name,
    ( SELECT aul.source
           FROM public.ai_usage_log aul
          WHERE ((aul.conversation_id)::text = (c.id)::text)
          ORDER BY aul.created_at
         LIMIT 1) AS source,
    ( SELECT
                CASE aul.source
                    WHEN 'metabot_agent'::text THEN 'Metabot'::character varying
                    WHEN 'agent'::text THEN 'Metabot'::character varying
                    WHEN 'document_generate_content'::text THEN 'Documents'::character varying
                    WHEN 'example_question_generation_batch'::text THEN 'Suggested Prompts'::character varying
                    WHEN 'slack'::text THEN 'Slackbot'::character varying
                    WHEN 'slackbot'::text THEN 'Slackbot'::character varying
                    WHEN 'oss-sql-gen'::text THEN 'SQL'::character varying
                    WHEN 'sql-gen'::text THEN 'SQL'::character varying
                    WHEN 'unknown'::text THEN 'Unknown'::character varying
                    ELSE aul.source
                END AS source
           FROM public.ai_usage_log aul
          WHERE ((aul.conversation_id)::text = (c.id)::text)
          ORDER BY aul.created_at
         LIMIT 1) AS source_name,
    c.ip_address,
    c.embedding_hostname,
    c.embedding_path,
    c.user_agent,
    c.sanitized_user_agent,
    max(a.tenant_id) AS tenant_id,
    max((t.name)::text) AS tenant_name,
    ( SELECT aul.model
           FROM public.ai_usage_log aul
          WHERE ((aul.conversation_id)::text = (c.id)::text)
          ORDER BY aul.created_at
         LIMIT 1) AS model
   FROM ((((public.metabot_conversation c
     LEFT JOIN public.core_user u ON ((u.id = c.user_id)))
     LEFT JOIN public.metabot_message m ON ((((m.conversation_id)::text = (c.id)::text) AND (m.deleted_at IS NULL))))
     LEFT JOIN ( SELECT ai_usage_log.conversation_id,
            COALESCE(sum(ai_usage_log.prompt_tokens), (0)::bigint) AS prompt_tokens,
            COALESCE(sum(ai_usage_log.completion_tokens), (0)::bigint) AS completion_tokens,
            COALESCE(sum(ai_usage_log.total_tokens), (0)::bigint) AS total_tokens,
            min(ai_usage_log.tenant_id) AS tenant_id
           FROM public.ai_usage_log
          WHERE (ai_usage_log.conversation_id IS NOT NULL)
          GROUP BY ai_usage_log.conversation_id) a ON (((a.conversation_id)::text = (c.id)::text)))
     LEFT JOIN public.tenant t ON ((t.id = a.tenant_id)))
  GROUP BY c.id, c.created_at, c.user_id, c.summary, u.first_name, u.last_name, u.email;


